php artisan prisoner:add '{"name":"Shuaib Abdur Raheem","first_name":"Shuaib","last_name":"Abdur Raheem","description":"Shuaib Abdur Raheem was the eldest of the four young Sunni Muslim men known as the Williamsburg Four. On January 18, 1973 — the same day members of the Nation of Islam murdered seven Sunni Muslims, including children, in the Washington, D.C. home of Hamaas Abdul Khaalis (the Hanafi Massacre) — he led Dawud Abdur Rahman, Yusuf A. Mussadiq, and Salih Ali Abdullah into John and Als Sporting Goods at Broadway and Melrose Street in Bushwick, Brooklyn, intending to acquire weapons to defend Sunni Muslim communities in New York from anticipated attack. A patron alerted the NYPD; the four attempted to surrender almost immediately but were fired on at the back door and forced back inside. The forty-eight-hour police siege that followed killed NYPD Officer Stephen Gilroy, who the defense and witnesses inside the store later confirmed had been shot by NYPD gunfire, not by the defendants.\n\nThe four were convicted in June 1974 of Officer Gilroys murder and sentenced to twenty-five years to life. Shuaib was granted parole in 2007 after serving 32 years; the parole grant was rescinded after a campaign by the NYPD and its supporters. He was finally released on parole on July 2, 2010, after 35 years in New York state prison.","state":"New York","race":"Black","gender":"Male","ideologies":["Sunni Islam","Black community self-defense"],"affiliation":["Williamsburg 4"],"in_custody":false,"released":true,"cases":[{"institution_name":"Eastern New York Correctional Facility","institution_city":"Napanoch","institution_state":"New York","charges":"Murder of NYPD Officer Stephen Gilroy during the January 1973 Bushwick police siege","arrest_date":"1973-01-19","incarceration_date":"1973-01-19","release_date":"2010-07-02","sentence":"25 years to life; paroled July 2010 after 35 years (initial 2007 parole grant rescinded after NYPD campaign)","convicted":"Yes — New York state jury verdict, June 1974"}]}'

php artisan prisoner:add '{"name":"Yusuf A. Mussadiq","first_name":"Yusuf","middle_name":"A.","last_name":"Mussadiq","description":"Yusuf A. Mussadiq was one of the four young Sunni Muslim men known as the Williamsburg Four. On January 18, 1973 he, with Shuaib Abdur Raheem, Dawud Abdur Rahman, and Salih Ali Abdullah, entered John and Als Sporting Goods at Broadway and Melrose Street in Bushwick, Brooklyn intending to acquire weapons to defend Sunni Muslim communities in New York after that days murders of seven Sunni Muslims by members of the Nation of Islam in Washington, D.C. (the Hanafi Massacre). The forty-eight-hour police siege that followed killed NYPD Officer Stephen Gilroy in police gunfire that the defense argued and inside-store witnesses later confirmed had not come from the defendants.\n\nThe four were convicted in June 1974 of Officer Gilroys murder and sentenced to twenty-five years to life. Mussadiq served twenty-five years before suffering a massive stroke that left him partially incapacitated. He was released on medical parole in 1998 and died on January 1, 2003.","state":"New York","race":"Black","gender":"Male","death_date":"2003-01-01","ideologies":["Sunni Islam","Black community self-defense"],"affiliation":["Williamsburg 4"],"in_custody":false,"released":true,"cases":[{"institution_name":"New York State Department of Corrections","institution_state":"New York","charges":"Murder of NYPD Officer Stephen Gilroy during the January 1973 Bushwick police siege","arrest_date":"1973-01-19","incarceration_date":"1973-01-19","release_date":"1998-12-01","sentence":"25 years to life; medical parole in 1998 after a stroke; died January 2003","convicted":"Yes — New York state jury verdict, June 1974"}]}'

