php artisan prisoner:add '{"name":"Hridindu Roychowdhury","first_name":"Hridindu","last_name":"Roychowdhury","description":"Hridindu Roychowdhury is an anarchist and former PhD student who in May 2022 — in the days following the leak of the U.S. Supreme Court draft opinion in Dobbs v. Jackson Womens Health Organization, which would overturn Roe v. Wade — set fire to the Madison, Wisconsin headquarters of Wisconsin Family Action, an anti-abortion lobbying group. Care was taken that no one was inside, and the only injuries were to the building. The graffiti left at the scene read: IF ABORTIONS ARENT SAFE, THEN YOU ARENT EITHER.\n\nThe FBI built its case against him by recovering DNA from a discarded burrito he had thrown out near the scene. He was indicted on federal arson and use-of-fire charges. In a non-cooperating plea agreement he pleaded guilty and accepted responsibility, and was sentenced to 90 months in federal prison. He is held at FCI Thomson, Illinois, federal inmate number 51111-510. The Anarchist Black Cross Federation lists him among its current anarchist movement political prisoners.","state":"Wisconsin","race":"Asian","gender":"Male","ideologies":["Anarchism","Reproductive rights"],"affiliation":[],"inmate_number":"51111-510","in_custody":true,"released":false,"cases":[{"institution_name":"FCI Thomson","institution_city":"Thomson","institution_state":"Illinois","charges":"Federal arson and use of fire to commit a federal felony — May 2022 attempted arson of the Wisconsin Family Action headquarters in Madison, in protest of the Supreme Courts pending Dobbs decision","arrest_date":"2023-03-29","incarceration_date":"2023-12-15","sentence":"90 months federal prison","convicted":"Yes — guilty plea (non-cooperating), 2023"}]}'

php artisan prisoner:add '{"name":"Andrew Mickel","first_name":"Andrew","last_name":"Mickel","description":"Andrew Hampton McCrae Mickel shot and killed Red Bluff, California police officer David Mobilio at a gas station on November 19, 2002. There were no eyewitnesses to the killing and the case might have gone unsolved had Mickel not posted to an internet anti-government discussion site six days later: Hello Everyone, my name’s Andy. I killed a Police Officer in Red Bluff, California in a motion to bring attention to, and halt, the police-state tactics that have come to be used throughout our country. He surrendered to authorities in Olympia, Washington shortly afterward.\n\nHe represented himself at trial in Tehama County in 2005 and presented a political defense, arguing the killing had been a justified act of resistance against the U.S. police state. The jury convicted him of one count of first-degree murder. He was sentenced to death in November 2005 and is held on Death Row at San Quentin State Prison, California Department of Corrections inmate number V77400. The Anarchist Black Cross Federation lists him among its current anti-police political prisoners.","state":"California","race":"White","gender":"Male","birthdate":"1979-01-01","ideologies":["Anti-police","Anti-government"],"inmate_number":"V77400","in_custody":true,"released":false,"cases":[{"institution_name":"San Quentin State Prison (Death Row)","institution_city":"San Quentin","institution_state":"California","charges":"First-degree murder of Red Bluff, California police officer David Mobilio (November 19, 2002)","arrest_date":"2002-11-26","incarceration_date":"2005-11-01","sentence":"Death — held on Death Row at San Quentin","convicted":"Yes — Tehama County, California jury verdict, April 2005"}]}'

