php artisan prisoner:add '{"name":"Christopher Tindal","first_name":"Christopher","last_name":"Tindal","description":"Christopher Tindal is a Rochester, New York father who was arrested in May 2020 in connection with the arson of a Rochester police car during the protests that followed the police murder of George Floyd. He pleaded guilty to a riot charge, which carried a lesser sentence than the underlying arson charge, and was sentenced to five years in federal prison. He is held at the United States Penitentiary at Big Sandy, Inez, Kentucky, federal inmate number 04392-509.\n\nIn his own words: What led up to me protesting George Floyd’s murder in 2020 was that all my life I’ve had run-ins with the police. I know what its like to be pinned under legs and knees, yelling I can’t breathe while foolish cops go stop yelling, then you’ll be able to breathe.","state":"New York","race":"Black","gender":"Male","ideologies":["Anti-police"],"inmate_number":"04392-509","in_custody":true,"released":false,"cases":[{"institution_name":"USP Big Sandy","institution_city":"Inez","institution_state":"Kentucky","charges":"Riot — arson of a Rochester, New York police car during the protests following the police murder of George Floyd","arrest_date":"2020-05-30","incarceration_date":"2020-05-30","sentence":"5 years federal prison","convicted":"Yes — guilty plea to riot count"}]}'

php artisan prisoner:add '{"name":"Khalif Miller","first_name":"Khalif","last_name":"Miller","description":"Khalif Miller is a North Philadelphia father and small business owner indicted in October 2020 by Trump U.S. Attorney General William Barrs Department of Justice on federal charges arising from the May–June 2020 protests in Philadelphia following the police murder of George Floyd. He was one of five Philadelphians charged in a coordinated indictment alongside Ant Smith. He was held on pretrial detention for two years before pleading and was sentenced to five years in federal prison. Because he was on probation at the time of his indictment, he was given an additional 1 to 10 year Pennsylvania state sentence for probation violation, to which he is now serving after completing his federal time. The Uprising Support project documented his case as one of the most aggressive examples of federal prosecution of 2020 uprising defendants.","state":"Pennsylvania","race":"Black","gender":"Male","ideologies":["Anti-police"],"inmate_number":"QQ9287","in_custody":true,"released":false,"cases":[{"institution_name":"SCI Forest","institution_city":"Marienville","institution_state":"Pennsylvania","charges":"Federal indictment by Trump AG William Barr arising from the 2020 Philadelphia protests following the police murder of George Floyd; subsequent Pennsylvania state probation violation sentence","arrest_date":"2020-10-15","incarceration_date":"2020-10-15","sentence":"5 years federal prison + 1 to 10 years Pennsylvania state for probation violation","convicted":"Yes — federal guilty plea after 2 years of pretrial detention; subsequent state probation violation"}]}'

php artisan prisoner:add '{"name":"Mujera Benjamin Lunga’ho","first_name":"Mujera","middle_name":"Benjamin","last_name":"Lunga’ho","description":"Mujera Benjamin Lunga’ho is a Little Rock, Arkansas defendant in the federal prosecution of the 2020 Little Rock uprising defendants — four people federally charged for the torching of Little Rock police vehicles during the protests that followed the police murder of George Floyd. He was incarcerated from September 2021 onward, and after pleading guilty to arson in August 2023 he was sentenced to five and a half years in federal prison. He is held at FCI Beaumont Medium in Texas, federal inmate number 08572-509. His three co-defendants — Renea Goddard, Cody Nowlin, and Angel Espinosa-Villegas — each received 18-month sentences on lesser explosives or conspiracy counts.","state":"Arkansas","race":"Black","gender":"Male","ideologies":["Anti-police"],"inmate_number":"08572-509","in_custody":true,"released":false,"cases":[{"institution_name":"FCI Beaumont Medium","institution_city":"Beaumont","institution_state":"Texas","charges":"Federal arson — torching of Little Rock, Arkansas police vehicles during the 2020 protests following the police murder of George Floyd","arrest_date":"2021-09-15","incarceration_date":"2021-09-15","sentence":"5.5 years federal prison","convicted":"Yes — guilty plea, August 2023"}]}'

php artisan prisoner:add '{"name":"Angel Espinosa-Villegas","first_name":"Angel","last_name":"Espinosa-Villegas","aka":"Loba","description":"Angel Espinosa-Villegas is a Chilean-born trans butch lesbian organizer who came to the United States at age seven and built her life in Chicago. She was one of the four Little Rock, Arkansas defendants — alongside Mujera Benjamin Lunga’ho, Renea Goddard, and Cody Nowlin — federally prosecuted for the torching of Little Rock police vehicles during the protests following the police murder of George Floyd. In September 2022 she pleaded guilty to possession of a Molotov cocktail and was sentenced to 18 months in federal prison, which she served at the Federal Medical Center at Carswell in Fort Worth, Texas.\n\nOn April 1, 2025, at the end of her federal sentence, she was taken into ICE custody for deportation to Chile. After several months in immigration detention she was deported and reunited with family in Chile, separated from her partner, family, and community in the United States.","state":"Arkansas","race":"Hispanic","gender":"Female","ideologies":["Anti-police","LGBTQ rights"],"in_custody":false,"released":true,"in_exile":true,"cases":[{"institution_name":"Federal Medical Center, Carswell","institution_city":"Fort Worth","institution_state":"Texas","charges":"Possession of a Molotov cocktail — Little Rock, Arkansas police-vehicle arsons during 2020 George Floyd protests","incarceration_date":"2024-01-01","release_date":"2025-04-01","sentence":"18 months federal prison + ICE detention pending deportation to Chile","convicted":"Yes — guilty plea, September 2022"}]}'

php artisan prisoner:add '{"name":"Alvin Joseph","first_name":"Alvin","last_name":"Joseph","description":"Alvin Joseph is a Gwinnett County, Georgia defendant who was arrested in June 2020 on federal charges of attempted arson of police vehicles during the protests that followed the police murder of George Floyd. He was held without bond at the Robert A. Deyton Detention Facility for nearly two years pretrial. After pleading guilty to attempted arson he was sentenced on March 8, 2022. He served his sentence in the federal Bureau of Prisons and was released in summer 2025.","state":"Georgia","race":"Black","gender":"Male","ideologies":["Anti-police"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Attempted arson of police vehicles in Gwinnett County, Georgia during the 2020 George Floyd protests","arrest_date":"2020-06-01","incarceration_date":"2020-06-01","release_date":"2025-08-01","sentence":"Federal sentence imposed March 2022; released summer 2025","convicted":"Yes — guilty plea, 2022"}]}'

php artisan prisoner:add '{"name":"Tyre Means","first_name":"Tyre","last_name":"Means","description":"Tyre Means was a Seattle defendant in the May 30, 2020 downtown Seattle protests following the police murder of George Floyd. He pleaded guilty in March 2021 to one count of arson and one count of possession of a stolen firearm, and was sentenced to five years in federal prison. At his sentencing he told the judge: the days of just rolling over to police brutality are over. He served his sentence and was released in August 2025.","state":"Washington","race":"Black","gender":"Male","ideologies":["Anti-police"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Washington","charges":"Federal arson and possession of a stolen firearm — May 30, 2020 Seattle protests following the police murder of George Floyd","arrest_date":"2020-06-15","incarceration_date":"2020-06-15","release_date":"2025-08-01","sentence":"5 years federal prison","convicted":"Yes — guilty plea, March 2021"}]}'

php artisan prisoner:add '{"name":"Renea Goddard","first_name":"Renea","last_name":"Goddard","description":"Renea Goddard is one of the four Little Rock, Arkansas defendants — alongside Mujera Benjamin Lunga’ho, Cody Nowlin, and Angel Espinosa-Villegas — federally prosecuted for the torching of Little Rock police vehicles during the protests that followed the police murder of George Floyd. In September 2022 she pleaded guilty to conspiracy to possess a Molotov cocktail and was sentenced to 18 months in federal prison. She began her sentence in 2024.","state":"Arkansas","race":"Black","gender":"Female","ideologies":["Anti-police"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Conspiracy to possess a Molotov cocktail — Little Rock, Arkansas police-vehicle arsons during 2020 George Floyd protests","incarceration_date":"2024-01-01","sentence":"18 months federal prison","convicted":"Yes — guilty plea, September 2022"}]}'

php artisan prisoner:add '{"name":"Cody Nowlin","first_name":"Cody","last_name":"Nowlin","description":"Cody Nowlin is one of the four Little Rock, Arkansas defendants — alongside Mujera Benjamin Lunga’ho, Renea Goddard, and Angel Espinosa-Villegas — federally prosecuted for the torching of Little Rock police vehicles during the protests that followed the police murder of George Floyd. In September 2022 he pleaded guilty to possession of a Molotov cocktail and was sentenced to 18 months in federal prison. He began his sentence in 2024.","state":"Arkansas","race":"White","gender":"Male","ideologies":["Anti-police"],"in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Possession of a Molotov cocktail — Little Rock, Arkansas police-vehicle arsons during 2020 George Floyd protests","incarceration_date":"2024-01-01","sentence":"18 months federal prison","convicted":"Yes — guilty plea, September 2022"}]}'

